import '../types';

import type { I18nMiddlewareConfig } from '@meli/i18n/middleware';

import { createI18nMiddleware } from '@meli/i18n/middleware';
import { config as feConfig } from 'frontend-config';

import { I18n as NordicI18n } from '../i18n';
import { setterCoreContextMiddleware } from './context';
import { i18nIVMiddleware, i18nLocaleMiddleware } from './backoffice';

export type NordicI18nMiddlewareConfig = Partial<
  Omit<I18nMiddlewareConfig, 'I18nClass'>
>;

/**
 * Creates an I18n instance per request, defining properties: `req.translations` and `req.i18n`.
 *
 * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/nordic-i18n#middlewares | Documentation}
 *
 * @example
 *
 * import ragnar from 'nordic/ragnar';
 * import { createNordicI18nMiddlewares } from 'nordic/i18n/middleware';
 *
 * const appRouter = router();
 *
 * appRouter.use(createNordicI18nMiddlewares());
 *
 */
export function createNordicI18nMiddlewares(
  config: NordicI18nMiddlewareConfig = feConfig.i18n ?? {},
) {
  const middlewares = [
    createI18nMiddleware({
      srcPath: config.srcPath,
      notifyMissingTranslations: config.notifyMissingTranslations,
      I18nClass: NordicI18n,
    }),
    setterCoreContextMiddleware,
  ];

  if (feConfig.intra) {
    middlewares.unshift(i18nIVMiddleware, i18nLocaleMiddleware);
  }

  return middlewares;
}

declare module 'express-serve-static-core' {
  interface Request {
    i18n?: NordicI18n;
  }
}
